pub(crate) fn tokenize(content: &str) -> Vec<Token> {
    let bytes = content.as_bytes();
    let mut tokens = Vec::new();
    let mut index = 0;
    while index < bytes.len() {
        match bytes[index] {
            b' ' | b'\t' | b'\r' => index += 1,
            b'\n' => {
                tokens.push(Token {
                    kind: TokenKind::Newline,
                    start: index,
                    end: index + 1,
                });
                index += 1;
            }
            b'/' if bytes.get(index + 1) == Some(&b'/') => {
                index += 2;
                while index < bytes.len() && bytes[index] != b'\n' {
                    index += 1;
                }
            }
            b'/' if bytes.get(index + 1) == Some(&b'*') => {
                index += 2;
                while index + 1 < bytes.len() && !(bytes[index] == b'*' && bytes[index + 1] == b'/')
                {
                    index += 1;
                }
                index = (index + 2).min(bytes.len());
            }
            quote @ (b'\'' | b'"') => {
                let start = index;
                index += 1;
                let mut value = String::new();
                while index < bytes.len() {
                    if bytes[index] == b'\\' {
                        if let Some(next) = bytes.get(index + 1) {
                            value.push(*next as char);
                            index += 2;
                        } else {
                            index += 1;
                        }
                    } else if bytes[index] == quote {
                        index += 1;
                        break;
                    } else {
                        value.push(bytes[index] as char);
                        index += 1;
                    }
                }
                tokens.push(Token {
                    kind: TokenKind::StringLiteral(value),
                    start,
                    end: index,
                });
            }
            b'`' => {
                index += 1;
                while index < bytes.len() {
                    if bytes[index] == b'\\' {
                        index = (index + 2).min(bytes.len());
                    } else if bytes[index] == b'`' {
                        index += 1;
                        break;
                    } else {
                        index += 1;
                    }
                }
            }
            byte if is_identifier_start(byte) => {
                let start = index;
                index += 1;
                while index < bytes.len() && is_identifier_continue(bytes[index]) {
                    index += 1;
                }
                tokens.push(Token {
                    kind: TokenKind::Identifier(content[start..index].to_string()),
                    start,
                    end: index,
                });
            }
            byte => {
                tokens.push(Token {
                    kind: TokenKind::Punctuation(byte as char),
                    start: index,
                    end: index + 1,
                });
                index += 1;
            }
        }
    }
    tokens
}

/// Preserve byte offsets and newlines while hiding comments and literal bodies
/// from regex-based definition extraction.
pub(crate) fn mask_non_code(content: &str) -> String {
    let bytes = content.as_bytes();
    let mut masked = bytes.to_vec();
    let mut index = 0;
    while index < bytes.len() {
        let start = index;
        match bytes[index] {
            b'/' if bytes.get(index + 1) == Some(&b'/') => {
                index += 2;
                while index < bytes.len() && bytes[index] != b'\n' {
                    index += 1;
                }
                mask_range(&mut masked, start, index);
            }
            b'/' if bytes.get(index + 1) == Some(&b'*') => {
                index += 2;
                while index + 1 < bytes.len() && !(bytes[index] == b'*' && bytes[index + 1] == b'/')
                {
                    index += 1;
                }
                index = (index + 2).min(bytes.len());
                mask_range(&mut masked, start, index);
            }
            quote @ (b'\'' | b'"' | b'`') => {
                index += 1;
                while index < bytes.len() {
                    if bytes[index] == b'\\' {
                        index = (index + 2).min(bytes.len());
                    } else if bytes[index] == quote {
                        index += 1;
                        break;
                    } else {
                        index += 1;
                    }
                }
                mask_range(&mut masked, start, index);
            }
            _ => index += 1,
        }
    }
    String::from_utf8(masked).expect("masking preserves UTF-8")
}

fn mask_range(bytes: &mut [u8], start: usize, end: usize) {
    for byte in &mut bytes[start..end] {
        if *byte != b'\n' {
            *byte = b' ';
        }
    }
}

pub(crate) fn callable_for_definition(
    tokens: &[Token],
    definition: usize,
    kind: &str,
) -> Option<Callable> {
    let (parameter_start, parameter_end, body_open) = if kind == "arrow" {
        let assignment = next_punctuation(tokens, definition + 1, '=')?;
        let parameter_start = next_punctuation(tokens, assignment + 1, '(')?;
        let parameter_end = matching_close(tokens, parameter_start, '(', ')')?;
        let arrow = outer_arrow_after(tokens, parameter_end)?;
        let body_open = next_punctuation(tokens, arrow + 2, '{')?;
        (parameter_start, parameter_end, body_open)
    } else {
        let parameter_start = next_punctuation(tokens, definition + 1, '(')?;
        let parameter_end = matching_close(tokens, parameter_start, '(', ')')?;
        let body_open = body_after_signature(tokens, parameter_end)?;
        (parameter_start, parameter_end, body_open)
    };
    let body_close = matching_close(tokens, body_open, '{', '}')?;
    Some(Callable {
        body_open,
        body_close,
        parameter_start,
        parameter_end,
    })
}

pub(crate) fn is_identifier_shadowed(tokens: &[Token], at: usize, name: &str) -> bool {
    is_identifier_shadowed_except(tokens, at, name, None)
}

pub(crate) fn is_identifier_shadowed_except(
    tokens: &[Token],
    at: usize,
    name: &str,
    allowed_binding_offset: Option<usize>,
) -> bool {
    let call_path = block_path(tokens, at);
    if call_path
        .iter()
        .filter_map(|body| callable_for_body(tokens, *body))
        .any(|callable| {
            parameter_binding_names(&tokens[callable.parameter_start + 1..callable.parameter_end])
                .iter()
                .any(|binding| binding == name)
        })
    {
        return true;
    }

    for index in 0..tokens.len() {
        let declaration = tokens[index].identifier();
        if !matches!(
            declaration,
            Some("const" | "let" | "var" | "function" | "class")
        ) || !declaration_binds_name(tokens, index, name)
        {
            continue;
        }
        if allowed_binding_offset
            .is_some_and(|offset| declaration_binding_at_offset(tokens, index, name, offset))
        {
            continue;
        }
        let declaration_path = if declaration == Some("var") {
            nearest_function_path(tokens, index)
        } else {
            block_path(tokens, index)
        };
        if is_path_prefix(&declaration_path, &call_path) {
            return true;
        }
    }
    false
}

fn declaration_binding_at_offset(
    tokens: &[Token],
    declaration: usize,
    name: &str,
    offset: usize,
) -> bool {
    match tokens[declaration].identifier() {
        Some("function" | "class") => {
            next_non_newline(tokens, declaration + 1).is_some_and(|index| {
                tokens[index].identifier() == Some(name) && tokens[index].start == offset
            })
        }
        Some("const" | "let" | "var") => {
            next_non_newline(tokens, declaration + 1).is_some_and(|index| {
                tokens[index].identifier() == Some(name) && tokens[index].start == offset
            })
        }
        _ => false,
    }
}

fn callable_for_body(tokens: &[Token], body_open: usize) -> Option<Callable> {
    for index in (0..body_open).rev() {
        let Some(name) = tokens[index].identifier() else {
            continue;
        };
        let kind = if name == "function" {
            continue;
        } else if previous_non_newline(tokens, index)
            .is_some_and(|previous| tokens[previous].identifier() == Some("function"))
        {
            "function"
        } else {
            "arrow"
        };
        if let Some(callable) = callable_for_definition(tokens, index, kind) {
            if callable.body_open == body_open {
                return Some(callable);
            }
        }
    }
    None
}

fn nearest_function_path(tokens: &[Token], at: usize) -> Vec<usize> {
    let path = block_path(tokens, at);
    match path
        .iter()
        .rposition(|body| callable_for_body(tokens, *body).is_some())
    {
        Some(index) => path[..=index].to_vec(),
        None => Vec::new(),
    }
}

fn declaration_binds_name(tokens: &[Token], declaration: usize, name: &str) -> bool {
    match tokens[declaration].identifier() {
        Some("function" | "class") => {
            next_non_newline(tokens, declaration + 1).and_then(|index| tokens[index].identifier())
                == Some(name)
        }
        Some("const" | "let" | "var") => {
            variable_declarators(tokens, declaration + 1)
                .iter()
                .any(|declarator| {
                    binding_names(declarator)
                        .iter()
                        .any(|binding| binding == name)
                        && !contains_bare_require_call(declarator)
                })
        }
        _ => false,
    }
}

pub(crate) fn variable_declarator_at(
    tokens: &[Token],
    declaration: usize,
    at: usize,
) -> Option<&[Token]> {
    variable_declarators_with_ranges(tokens, declaration + 1)
        .into_iter()
        .find(|(start, end)| at >= *start && at < *end)
        .map(|(start, end)| &tokens[start..end])
}

fn variable_declarators(tokens: &[Token], start: usize) -> Vec<&[Token]> {
    variable_declarators_with_ranges(tokens, start)
        .into_iter()
        .map(|(segment_start, segment_end)| &tokens[segment_start..segment_end])
        .collect()
}

fn variable_declarators_with_ranges(tokens: &[Token], start: usize) -> Vec<(usize, usize)> {
    let mut ranges = Vec::new();
    let mut segment_start = start;
    let mut round = 0usize;
    let mut square = 0usize;
    let mut curly = 0usize;
    let mut index = start;
    while index <= tokens.len() {
        let at_end = index == tokens.len();
        let newline_ends = !at_end
            && tokens[index].is_newline()
            && match previous_non_newline(tokens, index) {
                Some(previous) => !tokens[previous].is_punctuation(','),
                None => true,
            };
        let statement_end = !at_end
            && round == 0
            && square == 0
            && curly == 0
            && (tokens[index].is_punctuation(';')
                || newline_ends
                || tokens[index].is_punctuation('}'));
        let comma =
            !at_end && round == 0 && square == 0 && curly == 0 && tokens[index].is_punctuation(',');
        if at_end || statement_end || comma {
            ranges.push((segment_start, index));
            if at_end || statement_end {
                break;
            }
            segment_start = index + 1;
        } else if tokens[index].is_punctuation('(') {
            round += 1;
        } else if tokens[index].is_punctuation(')') {
            round = round.saturating_sub(1);
        } else if tokens[index].is_punctuation('[') {
            square += 1;
        } else if tokens[index].is_punctuation(']') {
            square = square.saturating_sub(1);
        } else if tokens[index].is_punctuation('{') {
            curly += 1;
        } else if tokens[index].is_punctuation('}') {
            curly = curly.saturating_sub(1);
        }
        index += 1;
    }
    ranges
}

pub(crate) fn binding_names(tokens: &[Token]) -> Vec<String> {
    let end = tokens
        .iter()
        .position(|token| token.is_punctuation('='))
        .unwrap_or(tokens.len());
    let binding = &tokens[..end];
    let mut bindings = Vec::new();
    if !binding
        .first()
        .is_some_and(|token| token.is_punctuation('{') || token.is_punctuation('['))
    {
        if let Some(first) = binding.iter().find_map(Token::identifier) {
            bindings.push(first.to_string());
            return bindings;
        }
    }
    for (index, token) in binding.iter().enumerate() {
        let Some(identifier) = token.identifier() else {
            continue;
        };
        if !binding
            .get(index + 1)
            .is_some_and(|next| next.is_punctuation(':'))
        {
            bindings.push(identifier.to_string());
        }
    }
    bindings
}

fn contains_bare_require_call(tokens: &[Token]) -> bool {
    tokens.iter().enumerate().any(|(index, token)| {
        token.identifier() == Some("require")
            && match previous_non_newline(tokens, index) {
                Some(previous) => !tokens[previous].is_punctuation('.'),
                None => true,
            }
            && next_non_newline(tokens, index + 1)
                .is_some_and(|next| tokens[next].is_punctuation('('))
    })
}

fn parameter_binding_names(tokens: &[Token]) -> Vec<String> {
    split_top_level(tokens, ',')
        .into_iter()
        .flat_map(binding_pattern_names)
        .collect()
}

fn binding_pattern_names(tokens: &[Token]) -> Vec<String> {
    let end = top_level_position(tokens, '=')
        .or_else(|| top_level_position(tokens, ':'))
        .unwrap_or(tokens.len());
    let pattern = &tokens[..end];
    if pattern
        .first()
        .is_some_and(|token| token.is_punctuation('{'))
    {
        let inner = &pattern[1..pattern.len().saturating_sub(1)];
        return split_top_level(inner, ',')
            .into_iter()
            .flat_map(|property| {
                if let Some(colon) = top_level_position(property, ':') {
                    binding_pattern_names(&property[colon + 1..])
                } else {
                    property
                        .iter()
                        .find_map(Token::identifier)
                        .map(|name| vec![name.to_string()])
                        .unwrap_or_default()
                }
            })
            .collect();
    }
    if pattern
        .first()
        .is_some_and(|token| token.is_punctuation('['))
    {
        let inner = &pattern[1..pattern.len().saturating_sub(1)];
        return split_top_level(inner, ',')
            .into_iter()
            .flat_map(binding_pattern_names)
            .collect();
    }
    pattern
        .iter()
        .find_map(Token::identifier)
        .map(|name| vec![name.to_string()])
        .unwrap_or_default()
}

fn split_top_level(tokens: &[Token], separator: char) -> Vec<&[Token]> {
    let mut result = Vec::new();
    let mut start = 0;
    let mut round = 0usize;
    let mut square = 0usize;
    let mut curly = 0usize;
    for (index, token) in tokens.iter().enumerate() {
        if round == 0 && square == 0 && curly == 0 && token.is_punctuation(separator) {
            result.push(&tokens[start..index]);
            start = index + 1;
        } else if token.is_punctuation('(') {
            round += 1;
        } else if token.is_punctuation(')') {
            round = round.saturating_sub(1);
        } else if token.is_punctuation('[') {
            square += 1;
        } else if token.is_punctuation(']') {
            square = square.saturating_sub(1);
        } else if token.is_punctuation('{') {
            curly += 1;
        } else if token.is_punctuation('}') {
            curly = curly.saturating_sub(1);
        }
    }
    result.push(&tokens[start..]);
    result
}

fn top_level_position(tokens: &[Token], punctuation: char) -> Option<usize> {
    split_top_level(tokens, punctuation)
        .first()
        .filter(|first| first.len() < tokens.len())
        .map(|first| first.len())
}

fn outer_arrow_after(tokens: &[Token], start: usize) -> Option<usize> {
    let mut round = 0usize;
    let mut square = 0usize;
    let mut curly = 0usize;
    for index in start + 1..tokens.len().saturating_sub(1) {
        if tokens[index].is_punctuation('(') {
            round += 1;
        } else if tokens[index].is_punctuation(')') {
            round = round.saturating_sub(1);
        } else if tokens[index].is_punctuation('[') {
            square += 1;
        } else if tokens[index].is_punctuation(']') {
            square = square.saturating_sub(1);
        } else if tokens[index].is_punctuation('{') {
            curly += 1;
        } else if tokens[index].is_punctuation('}') {
            curly = curly.saturating_sub(1);
        } else if round == 0
            && square == 0
            && curly == 0
            && tokens[index].is_punctuation('=')
            && tokens[index + 1].is_punctuation('>')
        {
            return Some(index);
        }
    }
    None
}

fn body_after_signature(tokens: &[Token], parameter_end: usize) -> Option<usize> {
    let mut cursor = next_non_newline(tokens, parameter_end + 1)?;
    if tokens[cursor].is_punctuation('{') {
        return Some(cursor);
    }
    if !tokens[cursor].is_punctuation(':') {
        return None;
    }
    cursor += 1;
    let mut round = 0usize;
    let mut square = 0usize;
    while cursor < tokens.len() {
        if tokens[cursor].is_punctuation('(') {
            round += 1;
        } else if tokens[cursor].is_punctuation(')') {
            round = round.saturating_sub(1);
        } else if tokens[cursor].is_punctuation('[') {
            square += 1;
        } else if tokens[cursor].is_punctuation(']') {
            square = square.saturating_sub(1);
        } else if round == 0 && square == 0 && tokens[cursor].is_punctuation('{') {
            let close = matching_close(tokens, cursor, '{', '}')?;
            let after = next_non_newline(tokens, close + 1);
            if let Some(after) = after {
                if tokens[after].is_punctuation('{') {
                    return Some(after);
                }
                if tokens[after].is_punctuation('|') || tokens[after].is_punctuation('&') {
                    cursor = close + 1;
                    continue;
                }
            }
            return Some(cursor);
        }
        cursor += 1;
    }
    None
}

fn block_path(tokens: &[Token], end: usize) -> Vec<usize> {
    let mut path = Vec::new();
    for (index, token) in tokens.iter().enumerate().take(end) {
        if token.is_punctuation('{') {
            path.push(index);
        } else if token.is_punctuation('}') {
            path.pop();
        }
    }
    path
}

fn is_path_prefix(prefix: &[usize], path: &[usize]) -> bool {
    prefix.len() <= path.len() && prefix.iter().zip(path).all(|(left, right)| left == right)
}

fn matching_close(tokens: &[Token], open: usize, left: char, right: char) -> Option<usize> {
    let mut depth = 0usize;
    for (index, token) in tokens.iter().enumerate().skip(open) {
        if token.is_punctuation(left) {
            depth += 1;
        } else if token.is_punctuation(right) {
            depth = depth.saturating_sub(1);
            if depth == 0 {
                return Some(index);
            }
        }
    }
    None
}

fn next_punctuation(tokens: &[Token], start: usize, punctuation: char) -> Option<usize> {
    (start..tokens.len()).find(|index| tokens[*index].is_punctuation(punctuation))
}

fn next_non_newline(tokens: &[Token], start: usize) -> Option<usize> {
    (start..tokens.len()).find(|index| !tokens[*index].is_newline())
}

fn previous_non_newline(tokens: &[Token], index: usize) -> Option<usize> {
    (0..index)
        .rev()
        .find(|previous| !tokens[*previous].is_newline())
}

fn is_identifier_start(byte: u8) -> bool {
    byte == b'_' || byte == b'$' || byte.is_ascii_alphabetic()
}

fn is_identifier_continue(byte: u8) -> bool {
    is_identifier_start(byte) || byte.is_ascii_digit()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn ignores_comments_strings_and_templates() {
        let tokens = tokenize("// ghost()\n/* hidden('x') */\n`template()`; real(); import './x';");
        let identifiers: Vec<&str> = tokens.iter().filter_map(Token::identifier).collect();
        assert_eq!(identifiers, vec!["real", "import"]);
        assert!(tokens
            .iter()
            .any(|token| token.string_literal() == Some("./x")));
    }

    #[test]
    fn callable_parser_skips_nested_defaults_and_return_type_braces() {
        let source = "const consumer = (callback = () => {}) => { dependency(); };";
        let tokens = tokenize(source);
        let definition = tokens
            .iter()
            .position(|token| token.identifier() == Some("consumer"))
            .unwrap();
        let callable = callable_for_definition(&tokens, definition, "arrow").unwrap();
        assert!(tokens[callable.body_open].start > source.find("=> {}").unwrap());

        let source = "function consumer({ flag }): () => { value: string } { dependency(); }";
        let tokens = tokenize(source);
        let definition = tokens
            .iter()
            .position(|token| token.identifier() == Some("consumer"))
            .unwrap();
        let callable = callable_for_definition(&tokens, definition, "function").unwrap();
        assert!(tokens[callable.body_open].start > source.find("value: string").unwrap());
        assert!(tokens[callable.parameter_start + 1..callable.parameter_end]
            .iter()
            .any(|token| token.identifier() == Some("flag")));
    }

    #[test]
    fn shadowing_handles_parameters_all_declarators_and_var_scope() {
        let source = "function scoped(require): void { require('x'); } require('real');";
        let tokens = tokenize(source);
        let calls: Vec<usize> = tokens
            .iter()
            .enumerate()
            .filter(|(_, token)| token.identifier() == Some("require"))
            .map(|(index, _)| index)
            .collect();
        assert!(is_identifier_shadowed(&tokens, calls[1], "require"));
        assert!(!is_identifier_shadowed(&tokens, calls[2], "require"));

        let source =
            "function consumer() { dependency(); const first = value,\n dependency = first; }";
        let tokens = tokenize(source);
        let call = tokens
            .iter()
            .position(|token| token.identifier() == Some("dependency"))
            .unwrap();
        assert!(is_identifier_shadowed(&tokens, call, "dependency"));

        let source =
            "function consumer() { dependency(); try { var dependency = local; } finally {} }";
        let tokens = tokenize(source);
        let call = tokens
            .iter()
            .position(|token| token.identifier() == Some("dependency"))
            .unwrap();
        assert!(is_identifier_shadowed(&tokens, call, "dependency"));
    }

    #[test]
    fn typed_function_and_arrow_parameters_shadow_require() {
        let source = "function scoped(require): () => void { require('ghost'); }";
        let tokens = tokenize(source);
        let calls: Vec<usize> = tokens
            .iter()
            .enumerate()
            .filter(|(_, token)| token.identifier() == Some("require"))
            .map(|(index, _)| index)
            .collect();
        assert!(is_identifier_shadowed(&tokens, calls[1], "require"));

        let source = "const scoped = (require): void => { require('ghost'); };";
        let tokens = tokenize(source);
        let calls: Vec<usize> = tokens
            .iter()
            .enumerate()
            .filter(|(_, token)| token.identifier() == Some("require"))
            .map(|(index, _)| index)
            .collect();
        assert!(is_identifier_shadowed(&tokens, calls[1], "require"));
    }
}
